```swift
// BinarySearchTree.swift
import Foundation

// Define a node structure for the BST
struct Node {
    var value: Int
    var left: Node?
    var right: Node?

    init(_ value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define the BST class
class BinarySearchTree {
    var root: Node?

    // Insert a new node into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    // Helper function to insert a node into the BST
    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else if value > node!.value {
            node!.right = insertNode(node!.right, value)
        }

        return node!
    }

    // Delete a node from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    // Helper function to delete a node from the BST
    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found, handle deletion
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children, find the in-order successor
                let successor = findInOrderSuccessor(node!.right)
                node!.value = successor.value
                node!.right = deleteNode(node!.right, successor.value)
            }
        }

        return node!
    }

    // Find the in-order successor of a node
    private func findInOrderSuccessor(_ node: Node?) -> Node? {
        var current = node
        var successor = nil

        while current != nil {
            successor = current
            current = current!.left
        }

        return successor
    }

    // Traversal functions
    // Pre-order: visit node, then left, then right
    func preOrderTraversal() {
        preOrderTraverse(root)
    }

    // In-order: left, visit node, right
    func inOrderTraversal() {
        inOrderTraverse(root)
    }

    // Post-order: left, right, visit node
    func postOrderTraversal() {
        postOrderTraverse(root)
    }

    // Helper functions for traversal
    private func preOrderTraverse(_ node: Node?) {
        if let node = node {
            print("Visit: $node.value")
            preOrderTraverse(node.left)
            preOrderTraverse(node.right)
        }
    }

    private func inOrderTraverse(_ node: Node?) {
        if let node = node {
            inOrderTraverse(node.left)
            print("Visit: $node.value")
            inOrderTraverse(node.right)
        }
    }

    private func postOrderTraverse(_ node: Node?) {
        if let node = node {
            postOrderTraverse(node.left)
            postOrderTraverse(node.right)
            print("Visit: $node.value")
        }
    }
}
```

### Explanation of Key Features:

- **Node Structure**: Each node contains a value and references to left and right children.
- **Insertion**: The `insert` method adds a new node to the correct position in the BST based on the value.
- **Deletion**: The `delete` method removes a node while maintaining the BST properties.
- **Traversal**:
  - **Pre-order**: Visit the node, then traverse the left subtree, then the right subtree.
  - **In-order**: Traverse the left subtree, visit the node, then traverse the right subtree.
  - **Post-order**: Traverse the left subtree, traverse the right subtree, then visit the node.

### Usage Example:

```swift
let bst = BinarySearchTree()
bst.insert(5)
bst.insert(3)
bst.insert(7)
bst.insert(2)
bst.insert(4)

print("Pre-order traversal:")
bst.preOrderTraversal()

print("\nIn-order traversal:")
bst.inOrderTraversal()

print("\nPost-order traversal:")
bst.postOrderTraversal()
```

This implementation is efficient and maintains the properties of a binary search tree, ensuring that operations like insertion, deletion, and traversal are performed in O(log n) time on average.

