# Function to merge two sorted arrays into one sorted array in descending order
sub merge {
    my ($left, $right) = @_;
    my @merged;

    # Base case: if either array is empty, return the other
    return @$left if !@$right;
    return @$right if !@$left;

    # If the left array is smaller, take elements from the left
    if ($left->[0] >= $right->[0]) {
        push @merged, $left->[0];
        return [ @$left[1..-1] ] . $merged;
    } else {
        push @merged, $right->[0];
        return [ @$right[1..-1] ] . $merged;
    }
}

# Function to perform merge sort on an array
sub merge_sort {
    my ($arr) = @_;
    return $arr if @$arr == 0;

    # Base case: if the array has only one element, return it
    return $arr if @$arr == 1;

    # Split the array into two halves
    my $mid = int(@$arr / 2);
    my $left = [$arr[0..$mid - 1]];
    my $right = [$arr[$mid..-1]];

    # Recursively sort both halves
    my $left_sorted = merge_sort($left);
    my $right_sorted = merge_sort($right);

    # Merge the two sorted halves
    my $merged = merge($left_sorted, $right_sorted);

    return $merged;
}

# Main program
